import {
  createElement,
  type ReactElement,
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react';
import { createRoot, type Root } from 'react-dom/client';
import { isElement } from 'react-is';

const getDataUri = (stringElement: string) => {
  return ['data:image/svg+xml;utf-8', stringElement].join(',');
};

const loadImage = (svgString: string): Promise<HTMLImageElement> => {
  const img = new Image();
  img.src = getDataUri(svgString);

  return new Promise((resolve) => {
    img.onload = () => {
      resolve(img);
    };
  });
};

const serializeColoredSvg = (svgNode: SVGElement, color: string): string => {
  svgNode.setAttribute('width', '16');
  svgNode.setAttribute('height', '16');
  svgNode.style.color = color;
  return new XMLSerializer().serializeToString(svgNode);
};

const resolveFromCacheOrLoad = async (
  serializedSvg: string,
  cache: Map<string, HTMLImageElement>,
): Promise<HTMLImageElement> => {
  const cached = cache.get(serializedSvg);
  if (cached) {
    return cached;
  }
  const image = await loadImage(serializedSvg);
  cache.set(serializedSvg, image);
  return image;
};

export const useBuildIconsDataUri = (icons: Array<[ReactElement, string]>) => {
  const [iconImages, setIconImages] = useState(
    new Map<ReactElement, HTMLImageElement>(),
  );
  const fakeDomContainerRef = useRef(document.createElement('div'));
  const rootRef = useRef<Root | null>(null);
  const svgImageCacheRef = useRef(new Map<string, HTMLImageElement>());

  const buildIconImages = useCallback(
    async (svgElements: HTMLCollectionOf<SVGElement>) => {
      const nextIconImages = new Map<ReactElement, HTMLImageElement>();

      for (let i = 0; i < icons.length; i++) {
        const [icon, color] = icons[i];

        if (isElement(icon)) {
          const svgNode = svgElements[i];
          if (!svgNode) {
            break;
          }

          const serialized = serializeColoredSvg(svgNode, color);
          nextIconImages.set(
            icon,
            await resolveFromCacheOrLoad(serialized, svgImageCacheRef.current),
          );
        }
      }

      setIconImages(nextIconImages);
    },
    [icons],
  );

  useEffect(() => {
    if (!rootRef.current) {
      rootRef.current = createRoot(fakeDomContainerRef.current);
    }

    rootRef.current.render(
      createElement(
        'div',
        {
          ref: (node: HTMLDivElement | null) => {
            if (node !== null) {
              void buildIconImages(node.getElementsByTagName('svg'));
            }
          },
        },
        icons,
      ),
    );
  }, [icons, buildIconImages]);

  return iconImages;
};
